class User {
  readonly id: string;
  name: string;
  private age: number;

  constructor(id: string, name: string, age: number) {
    this.id = id;
    this.name = name;
    this.age = age;
  }
}

class User {
  constructor(
    readonly id: string,
    public name: string,
    private age: number
  ) {}

  getAge(): number {
    return this.age;
  }
}

class Admin extends User {
  constructor(
    id: string,
    name: string,
    age: number,
    public permissions: string[]
  ) {
    super(id, name, age);
  }

  hasPermission(perm: string): boolean {
    return this.permissions.includes(perm);
  }
}

type Constructor<T = {}> = new (...args: any[]) => T;

function Loggable<TBase extends Constructor>(Base: TBase) {
  return class extends Base {
    log(message: string): void {
      console.log(`[${new Date().toISOString()}] ${message}`);
    }
  };
}

const LoggableUser = Loggable(User);

const user = new LoggableUser("u1", "Анна", 25);
user.log("Пользователь создан");
// [2026-03-15T10:00:00.000Z] Пользователь создан

console.log(user.name); // "Анна"

function Timestamped<TBase extends Constructor>(Base: TBase) {
  return class extends Base {
    createdAt = new Date();
  };
}

const EnhancedUser = Timestamped(Loggable(User));

const user = new EnhancedUser("u2", "Борис", 30);
user.log("Создан");           // метод из Loggable
console.log(user.createdAt);   // поле из Timestamped
console.log(user.name);        // поле из User
